#include <SPI.h>
#include <Wire.h>
#include <Adafruit_MAX31855.h>

extern int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float* intg,float* lastE);

Adafruit_MAX31855 tc(4);
const int TRIAC_PIN=9,SOLENOID_PIN=7;
const float KP=1.5f,KI=0.05f,KD=1.0f,TEMP_MAX=1400.0f;
float intg=0,lastE=0;

struct Segment{float temp;float ramp;unsigned long dwell_s;};
Segment profile[]={{600,5,300},{1100,10,600},{1320,5,7200},{400,-3,0},{25,-5,0}};
const int N_SEG=5;
int seg_idx=0;
float seg_sp=25.0f;
unsigned long dwell_start=0;
bool in_dwell=false;

// === Thermocouple ===
float tc_read(){double v=tc.readCelsius();if(isnan(v)){Serial.println("FAULT:TC");return -999.0f;}return(float)v;}

// === TRIAC Actuator ===
void triac_init(){pinMode(TRIAC_PIN,OUTPUT);analogWrite(TRIAC_PIN,0);}
void triac_set(int p){analogWrite(TRIAC_PIN,constrain(p,0,255));}

// === Atmosphere Control ===
void atmosphere_init(){pinMode(SOLENOID_PIN,OUTPUT);digitalWrite(SOLENOID_PIN,LOW);}
void atmosphere_ctrl(float temp){digitalWrite(SOLENOID_PIN,(temp>400.0f&&temp<1350.0f)?HIGH:LOW);}

// === Profile Scheduler ===
void profile_advance(float pv,unsigned long now){
  if(seg_idx>=N_SEG-1)return;
  if(!in_dwell){seg_sp+=profile[seg_idx].ramp/60.0f;if((profile[seg_idx].ramp>0&&seg_sp>=profile[seg_idx].temp)||(profile[seg_idx].ramp<0&&seg_sp<=profile[seg_idx].temp)){seg_sp=profile[seg_idx].temp;in_dwell=true;dwell_start=now;}}
  else{if(now-dwell_start>=profile[seg_idx].dwell_s*1000UL){seg_idx++;in_dwell=false;}}}

// === Fault Handler ===
bool fault_check(float t){if(t<-100.0f||t>TEMP_MAX){triac_set(0);digitalWrite(SOLENOID_PIN,LOW);Serial.println("FAULT:FURNACE");return true;}return false;}

void setup(){
  Serial.begin(115200);Wire.begin();
  tc.begin();triac_init();atmosphere_init();
  Serial.println("t_s,sp,pv,pwm,seg");
}

unsigned long lastMs=0;
void loop(){
  unsigned long now=millis();
  float dt=(now-lastMs)/1000.0f;
  if(dt<0.25f)return;lastMs=now;
  float pv=tc_read();
  if(fault_check(pv))return;
  profile_advance(pv,now);
  int pwm=pid_heater_control(seg_sp,pv,dt,KP,KI,KD,&intg,&lastE);
  triac_set(pwm);
  atmosphere_ctrl(pv);
  if((int)(now/1000)%5==0){Serial.print(now/1000);Serial.print(',');Serial.print(seg_sp,0);Serial.print(',');Serial.print(pv,1);Serial.print(',');Serial.print(pwm);Serial.print(',');Serial.println(seg_idx);}
}
